// TG-137: Fetch all daily briefing data in one code node
const supabaseUrl = 'https://lwtmvzhwekgdxkaisfra.supabase.co/rest/v1';
const supabaseKey = 'sb_publishable_DeX21ldoDKl3NyJeFZzR1w_eWBUkx-v';
const supabaseHeaders = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`
};

const now = new Date();
const yesterday = new Date(now.getTime() - 24 * 60 * 60 * 1000).toISOString();

// 1. New leads (last 24h)
let leads = [];
try {
  leads = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/leads?created_at=gte.${yesterday}&select=id,name,source,phone,created_at&order=created_at.desc`,
    headers: supabaseHeaders
  });
} catch (e) { leads = []; }

// 2. Pending follow-ups (follow_up_stage > 0 and < 5)
let followUps = [];
try {
  followUps = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/leads?follow_up_stage=gt.0&follow_up_stage=lt.5&select=id,name,follow_up_stage,next_follow_up`,
    headers: supabaseHeaders
  });
} catch (e) { followUps = []; }

// 3. Today's jobs from jobber_email_events
let jobs = [];
try {
  const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate()).toISOString();
  const todayEnd = new Date(now.getFullYear(), now.getMonth(), now.getDate() + 1).toISOString();
  jobs = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/jobber_email_events?event_date=gte.${todayStart}&event_date=lt.${todayEnd}&select=id,event_type,client_name,job_description`,
    headers: supabaseHeaders
  });
} catch (e) { jobs = []; }

// 4. Weather for Madison WI (free, no key)
let weather = null;
try {
  weather = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://wttr.in/Madison+WI?format=j1',
    headers: { 'Accept': 'application/json' }
  });
} catch (e) { weather = null; }

// 5. Recent Google reviews (last 24h)
let reviews = [];
try {
  reviews = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/google_reviews?created_at=gte.${yesterday}&select=id,author_name,rating,text,created_at`,
    headers: supabaseHeaders
  });
} catch (e) { reviews = []; }

// 6. n8n execution errors (last 20)
let errors = [];
try {
  errors = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://tgyardcare.app.n8n.cloud/api/v1/executions?limit=20&status=error',
    headers: {
      'X-N8N-API-KEY': 'N8N_API_KEY_PLACEHOLDER'
    }
  });
  if (errors && errors.data) errors = errors.data;
} catch (e) { errors = []; }

return [{
  json: {
    leads: Array.isArray(leads) ? leads : [],
    followUps: Array.isArray(followUps) ? followUps : [],
    jobs: Array.isArray(jobs) ? jobs : [],
    weather,
    reviews: Array.isArray(reviews) ? reviews : [],
    errors: Array.isArray(errors) ? errors : []
  }
}];

// TG-137: Build formatted Telegram briefing message
const data = $input.first().json;

const now = new Date();
const dateStr = now.toLocaleDateString('en-US', {
  timeZone: 'America/Chicago',
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric'
});

// Weather section
let weatherSection = 'Unavailable';
if (data.weather && data.weather.current_condition && data.weather.current_condition[0]) {
  const w = data.weather.current_condition[0];
  const tempF = w.temp_F || '?';
  const desc = w.weatherDesc && w.weatherDesc[0] ? w.weatherDesc[0].value : 'Unknown';
  const humidity = w.humidity || '?';
  const windMph = w.windspeedMiles || '?';
  weatherSection = `${tempF}\u00b0F ${desc}\nHumidity: ${humidity}% | Wind: ${windMph} mph`;
}

// Leads section
const leads = data.leads || [];
let leadsList = '';
if (leads.length > 0) {
  leadsList = leads.slice(0, 10).map(l => {
    const name = l.name || 'Unknown';
    const source = l.source || '?';
    return `  \u2022 ${name} (${source})`;
  }).join('\n');
} else {
  leadsList = '  None';
}
const followUps = data.followUps || [];

// Schedule section
const jobs = data.jobs || [];

// Reviews section
const reviews = data.reviews || [];
let reviewsList = '';
if (reviews.length > 0) {
  reviewsList = reviews.slice(0, 5).map(r => {
    const stars = '\u2b50'.repeat(Math.min(r.rating || 0, 5));
    return `  ${stars} ${r.author_name || 'Anonymous'}`;
  }).join('\n');
}

// Errors section
const errors = data.errors || [];

// Build full message
const lines = [
  `\ud83d\udcca TOTALGUARD DAILY BRIEFING`,
  dateStr,
  '',
  `\u2600\ufe0f WEATHER`,
  weatherSection,
  '',
  `\ud83d\udce5 LEADS (${leads.length} new)`,
  leadsList,
  `Pending follow-ups: ${followUps.length}`,
  '',
  `\ud83d\udcc5 SCHEDULE`,
  `${jobs.length} jobs today`,
  '',
  `\u2b50 REVIEWS (${reviews.length} new)`,
  reviews.length > 0 ? reviewsList : '  None',
  '',
  `\u2699\ufe0f SYSTEM`,
  `Errors (24h): ${errors.length}`,
  '',
  `Have a great day! \ud83d\ude80`
];

return [{ json: { message: lines.join('\n') } }];
